// claim-office.spec.ts
import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("Claim Office", () => {
  describe("quote: base premiums", () => {
    it.todo("should return premium 5 for an empty item list (only processing fee)");
    it.todo(
      "should quote a single sword for a newcomer at 115 (100 base + 10% first insurance + 5 fee)"
    );
    it.todo(
      "should quote a single amulet for a newcomer at 71 (60 base + 10% first insurance + 5 fee)"
    );
    it.todo(
      "should quote a single staff for a newcomer at 93 (80 base + 10% first insurance + 5 fee)"
    );
    it.todo(
      "should quote a single potion for a newcomer at 49 (40 base + 10% first insurance + 5 fee)"
    );
    it.todo("should charge 25 base premium per component (2 runes → base premium 50)");
  });

  describe("quote: building block of 3 alike components", () => {
    it.todo("should price a block of exactly 3 runes at base premium 60");
    it.todo("should not apply the block to 4 runes (base premium 100 — block requires exactly 3)");
    it.todo("should not apply the block to 7 runes (base premium 175)");
    it.todo(
      "should not form a block from different component types (2 runes + 1 moonstone → base premium 75)"
    );
    it.todo(
      "should form two separate blocks for 3 runes + 3 moonstones (base premium 120)"
    );
  });

  describe("quote: item-level modifiers", () => {
    it.todo("should add 50% curse surcharge to a cursed item's base premium");
    it.todo("should add 30% high-enchantment surcharge for enchantment exactly 5");
    it.todo("should not add the high-enchantment surcharge for enchantment 4");
    it.todo("should stack curse and high-enchantment surcharges on the same item");
    it.todo(
      "should apply the curse surcharge only to the cursed item's base premium, not the whole policy (cursed sword + plain amulet → policy base 210 before policy modifiers and fee)"
    );
  });

  describe("quote: policy-level modifiers", () => {
    it.todo("should apply the 20% loyalty discount for a customer with exactly 2 years with MHPCO");
    it.todo("should not apply the loyalty discount for a customer with fewer than 2 years");
    it.todo("should apply the 15% follow-up discount on the customer's second quote in the scenario");
    it.todo(
      "should quote a newcomer's cursed steel sword (enchantment 3) at 165 (100 + 50 curse + 10 first insurance + 5 fee)"
    );
    it.todo(
      "should quote a 3-year customer's second quote for a cursed sword (enchantment 7) at 160 (100 + 50 + 30 − 20 loyalty + 10 first − 15 follow-up + 5 fee)"
    );
  });

  describe("quote: rounding", () => {
    it.todo(
      "should round the final premium up to a whole G, keeping intermediates fractional (7 runes for a newcomer: 175 × 1.10 + 5 = 197.5 → 198)"
    );
  });

  describe("quote: errors", () => {
    it.todo("should throw an error for an unknown item type (e.g. broomstick)");
  });

  describe("claim: standard reimbursement", () => {
    it.todo(
      "should pay damage minus 100 deductible for a regular item (steel sword enchantment 3, damage 500 → payout 400)"
    );
    it.todo(
      "should pay damage minus 100 deductible for a component (rune, damage 200 → payout 100)"
    );
    it.todo("should include payout and remainingCap in a claim result");
  });

  describe("claim: special reimbursement clauses", () => {
    it.todo(
      "should reimburse 50% for enchantment ≥ 8 before deductible (steel sword enchantment 9, damage 1000 → payout 400)"
    );
    it.todo(
      "should fully reimburse dragon-material items before deductible (dragon sword enchantment 5, damage 800 → payout 700)"
    );
    it.todo(
      "should let the 50% rule win when both clauses apply (dragon sword enchantment 9, damage 1000 → payout 400)"
    );
    it.todo(
      "should apply the 50% rule at exactly enchantment 8 (dragon sword enchantment 8, damage 1000 → payout 400)"
    );
  });

  describe("claim: multiple damages in one incident", () => {
    it.todo(
      "should apply the deductible once per damaged item (sword 500 + amulet 300 → payout 600)"
    );
    it.todo(
      "should treat two damage entries for two insured swords as separate damages with their own deductibles"
    );
  });

  describe("claim: payout cap", () => {
    it.todo("should cap the payout at twice the insurance sum (single sword → cap 2000)");
    it.todo(
      "should compute the insurance sum from item values for multiple items (sword + amulet → insurance sum 1600, cap 3200)"
    );
    it.todo("should compute the cap for two swords (insurance sum 2000, cap 4000)");
    it.todo(
      "should not let premium modifiers change the cap (cursed sword → cap still 2000)"
    );
    it.todo(
      "should not let the block discount affect the insurance sum (sword + 3 runes → insurance sum 1750)"
    );
    it.todo(
      "should deplete the cap across successive claims (sword, two claims of 1500: first payout 1400 / remainingCap 600, second payout 600 / remainingCap 0)"
    );
  });

  describe("claim: rounding", () => {
    it.todo("should round the final payout down to a whole G");
  });

  describe("claim: errors", () => {
    it.todo("should throw an error for a damage entry whose item type is not in the policy");
    it.todo("should throw an error for a damage entry with an unknown item type");
    it.todo(
      "should throw an error when damages contain more entries of a type than insured items of that type"
    );
    it.todo("should throw an error for a negative damage amount");
  });

  describe("scenario processing", () => {
    it.todo(
      "should return one result per step in input order (quote → {premium}, claim → {payout, remainingCap})"
    );
  });
});
